import psycopg2

def search_users(**kwargs):
    conn = psycopg2.connect(
        database="your_database",
        user="your_username",
        password="your_password",
        host="your_host",
        port="your_port"
    )
    
    cur = conn.cursor()
    
    query = """
        SELECT *
        FROM users
        WHERE {}
    """.format(" AND ".join("{}=%s".format(key) for key in kwargs))
    
    try:
        cur.execute(query, list(kwargs.values()))
        
        rows = cur.fetchall()
        
        return [{'id': row[0], 'username': row[1], 'email': row[2], 'role': row[3], 'status': row[4]} for row in rows]
    
    finally:
        conn.close()

